<?php
$duzenleNo = $_GET['duzenle'] ?? '';
$duzenleData = null;
if ($duzenleNo) {
    $stmt = $pdo->prepare("SELECT f.*, m.kod as musteri_kod, m.ad as musteri_adi, m.vergi_no, m.efatura_tipi, m.iskonto_orani FROM faturalar f JOIN musteriler m ON f.musteri_id = m.id WHERE f.fatura_no = ?");
    $stmt->execute([$duzenleNo]);
    $duzenleData = $stmt->fetch(PDO::FETCH_ASSOC);
    if ($duzenleData) {
        $satirStmt = $pdo->prepare("SELECT fs.*, u.kod as urun_kod, b.birim_adi FROM fatura_satirlari fs LEFT JOIN urunler u ON fs.urun_id = u.id LEFT JOIN birimler b ON u.birim_ref = b.ref_id WHERE fs.fatura_id = ? ORDER BY fs.sira");
        $satirStmt->execute([$duzenleData['id']]);
        $duzenleData['satirlar'] = $satirStmt->fetchAll(PDO::FETCH_ASSOC);
    }
}
