<script>
function showToast(msg, isError) { let t=document.querySelector('.toast-notify'); if(!t){ t=document.createElement('div'); t.className='toast-notify'; document.body.appendChild(t); } t.textContent=msg; t.style.backgroundColor=isError?'#dc2626':'#22c55e'; t.style.opacity='1'; setTimeout(()=>t.style.opacity='0',2000); }
function calcPress(v) { let inp=document.getElementById('calcInput'); if(v==='C'){ window.calcExpr=''; inp.value='0'; }else if(v==='='){ try{ let r=eval(window.calcExpr); inp.value=r; window.calcExpr=r.toString(); }catch(e){ inp.value='Hata'; } }else{ if(!window.calcExpr || window.calcExpr==='0' && /[0-9]/.test(v)) window.calcExpr=v; else window.calcExpr+=v; inp.value=window.calcExpr; } }
function openCalculator() { let m=document.getElementById('calcModal'); if(m) m.style.display='flex'; document.getElementById('calcInput').value='0'; window.calcExpr=''; }
function closeCalculator() { document.getElementById('calcModal').style.display='none'; }
function addNewRow() { let tbody=document.querySelector('#faturaTable tbody'); if(!tbody) return; let row=document.createElement('tr'); row.className='urun-satir'; let isk=window.musteriIskonto||0; row.innerHTML='<td><input type="text" class="urun-kod" placeholder="Kod"></td><td><input type="text" class="urun-ad" readonly></td><td><input type="text" class="birim" readonly></td><td><input type="number" class="miktar" step="any" value="" placeholder="0"></td><td><input type="number" class="fiyat" step="any" value="" placeholder="0"></td><td><input type="number" class="iskonto" value="'+isk+'"></td><td><input type="text" class="tutar" readonly></td>'; tbody.appendChild(row); attachRowEvents(row); return row; }
function attachRowEvents(row) { row.querySelector('.urun-kod')?.addEventListener('keydown',e=>handleUrunKod(e,row)); row.querySelector('.miktar')?.addEventListener('keydown',e=>handleMiktar(e,row)); row.querySelector('.fiyat')?.addEventListener('keydown',e=>handleFiyat(e,row)); }
function handleUrunKod(e,row){ if(e.key==='Enter'){ e.preventDefault(); let k=row.querySelector('.urun-kod').value.trim(); if(k) fetchUrun(k,row,true); }else if(e.key==='ArrowDown'){ e.preventDefault(); let k=row.querySelector('.urun-kod').value.trim(); if(k) fetchUrun(k,row,false); let nr=row.nextElementSibling; if(!nr) nr=addNewRow(); setTimeout(()=>nr.querySelector('.urun-kod').focus(),50); }else if(e.key==='ArrowUp'){ e.preventDefault(); let k=row.querySelector('.urun-kod').value.trim(); if(k) fetchUrun(k,row,false); let pr=row.previousElementSibling; if(pr) pr.querySelector('.urun-kod').focus(); } }
function handleMiktar(e,row){ if(e.key==='Enter'){ e.preventDefault(); row.querySelector('.fiyat').focus(); }else if(e.key==='ArrowDown'){ e.preventDefault(); let nr=row.nextElementSibling; if(!nr) nr=addNewRow(); setTimeout(()=>nr.querySelector('.miktar').focus(),50); }else if(e.key==='ArrowUp'){ e.preventDefault(); let pr=row.previousElementSibling; if(pr) pr.querySelector('.miktar').focus(); } }
function handleFiyat(e,row){ if(e.key==='Enter'){ e.preventDefault(); hesaplaTutar(row); let nr=row.nextElementSibling; if(!nr) nr=addNewRow(); setTimeout(()=>nr.querySelector('.urun-kod').focus(),50); }else if(e.key==='ArrowDown'){ e.preventDefault(); hesaplaTutar(row); let nr=row.nextElementSibling; if(!nr) nr=addNewRow(); setTimeout(()=>nr.querySelector('.fiyat').focus(),50); }else if(e.key==='ArrowUp'){ e.preventDefault(); hesaplaTutar(row); let pr=row.previousElementSibling; if(pr) pr.querySelector('.fiyat').focus(); } }
function fetchUrun(kod,row,enterMod){ fetch('ajax/urun_getir.php?kod='+encodeURIComponent(kod)).then(r=>r.json()).then(data=>{ if(data.success){ row.querySelector('.urun-ad').value=data.ad; row.querySelector('.birim').value=data.birim_adi; row.querySelector('.miktar').value=''; row.querySelector('.fiyat').value=''; if(enterMod) row.querySelector('.miktar').focus(); showToast(data.ad+' eklendi'); }else{ if(confirm('"'+kod+'" kayıtlı değil. Yeni ürün eklemek ister misiniz?')) urunModalGoster(kod); } }); }
function hesaplaTutar(row){ let m=parseFloat(row.querySelector('.miktar').value)||0; let f=parseFloat(row.querySelector('.fiyat').value)||0; let i=parseFloat(row.querySelector('.iskonto').value)||0; let t=m*f; if(i>0) t=t*(1-i/100); row.querySelector('.tutar').value=t>0?t.toFixed(2):''; genelToplamHesapla(); }
function genelToplamHesapla(){ let toplam=0; document.querySelectorAll('.tutar').forEach(t=>{ let v=parseFloat(t.value); if(!isNaN(v) && v>0) toplam+=v; }); let kdv=parseFloat(document.getElementById('kdvOran').value)||1; let kdvT=toplam*kdv/100; let genel=toplam+kdvT; document.getElementById('malToplam').innerText=toplam.toFixed(2); document.getElementById('kdvTutar').innerText=kdvT.toFixed(2); document.getElementById('genelToplam').innerText=genel.toFixed(2); }
function musteriAra(aranan){ fetch('ajax/musteri_ara.php?q='+encodeURIComponent(aranan)).then(r=>r.json()).then(data=>{ if(data.length===1) musteriSec(data[0]); else if(data.length>1) musteriListeModal(data); else { document.getElementById('musteriBilgi').innerHTML='<span class="text-danger">Müşteri bulunamadı!</span>'; showToast('Müşteri bulunamadı',true); } }); }
function musteriSec(m){ document.getElementById('musteriKod').value=m.kod; document.getElementById('musteriBilgi').innerHTML='<strong>'+m.ad+'</strong><br>Vergi No: '+(m.vergi_no||'-')+' - '+m.efatura_tipi+'<br>🏷️ İskonto: %'+(m.iskonto_orani||0); showToast('Müşteri bulundu: '+m.ad); window.musteriIskonto=m.iskonto_orani||0; document.querySelectorAll('.iskonto').forEach(i=>i.value=window.musteriIskonto); }
function musteriListeModal(liste){ let html='<div id="musteriListeModal" class="musteri-modal"><div class="musteri-modal-content"><h4>Müşteri Seçin</h4><div id="modalListe">'; liste.forEach(m=>{ html+='<div class="list-group-item list-group-item-action" onclick="musteriSec('+JSON.stringify(m)+')"><strong>'+m.kod+'</strong> - '+m.ad+'<br><small>'+(m.vergi_no||'')+' | '+m.efatura_tipi+' | İskonto: %'+(m.iskonto_orani||0)+'</small></div>'; }); html+='</div><button class="btn btn-secondary mt-2" onclick="this.parentElement.parentElement.remove()">Kapat</button></div></div>'; document.body.insertAdjacentHTML('beforeend',html); }
function musteriAraModal(){ let d=document.getElementById('musteriKod').value.trim(); if(d.length<2) showToast('En az 2 karakter',true); else fetch('ajax/musteri_ara.php?q='+encodeURIComponent(d)).then(r=>r.json()).then(data=>{ if(data.length) musteriListeModal(data); else showToast('Müşteri bulunamadı',true); }); }
function urunModalGoster(yeniKod){ let m=document.getElementById('urunModal'); if(m) m.style.display='flex'; if(yeniKod){ document.getElementById('urunKod').value=yeniKod; document.getElementById('urunAd').focus(); } urunListele(); }
function urunListele(){ fetch('ajax/urun_listele.php').then(r=>r.json()).then(data=>{ let liste=document.getElementById('urunListesi'); if(!liste) return; liste.innerHTML=''; data.forEach(u=>{ let d=document.createElement('div'); d.className='list-group-item list-group-item-action'; d.innerHTML='<strong>'+u.kod+'</strong> - '+u.ad+' ('+u.birim_adi+') KDV:'+u.varsayilan_kdv+'%'; d.onclick=()=>{ document.getElementById('urunKod').value=u.kod; document.getElementById('urunAd').value=u.ad; document.getElementById('urunBirimRef').value=u.birim_ref; document.getElementById('urunKdv').value=u.varsayilan_kdv; }; liste.appendChild(d); }); }); }
function urunKaydet(){ let kod=document.getElementById('urunKod').value; let ad=document.getElementById('urunAd').value; let br=document.getElementById('urunBirimRef').value; let kdv=document.getElementById('urunKdv').value; fetch('ajax/urun_kaydet.php',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'kod='+encodeURIComponent(kod)+'&ad='+encodeURIComponent(ad)+'&birim_ref='+br+'&kdv='+kdv}).then(r=>r.json()).then(data=>{ if(data.success){ showToast('Ürün kaydedildi'); urunModalKapat(); }else{ showToast('Hata: '+data.error,true); } }); }
function urunModalKapat(){ document.getElementById('urunModal').style.display='none'; }
function yeniBirimEkle(){ let yb=prompt('Yeni birim adı girin:'); if(yb){ fetch('ajax/birim_ekle.php',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:'birim_adi='+encodeURIComponent(yb)}).then(r=>r.json()).then(data=>{ if(data.success) showToast('Birim eklendi. Ref ID: '+data.ref_id); else showToast('Hata: '+data.error,true); }); } }
document.getElementById('musteriKod').addEventListener('input',function(e){ clearTimeout(window.mt); let d=this.value.trim(); if(d.length>=2) window.mt=setTimeout(()=>musteriAra(d),500); });
document.getElementById('musteriKod').addEventListener('keypress',function(e){ if(e.key==='Enter'){ e.preventDefault(); musteriAra(this.value.trim()); } });
document.getElementById('toggleOdeme').onclick=()=>{ let tip=document.getElementById('odemeTipi').value==='Peşin'?'Veresiye':'Peşin'; document.getElementById('odemeTipi').value=tip; document.getElementById('toggleOdeme').innerHTML='💰 '+tip+' <kbd>F7</kbd>'; showToast('Ödeme tipi: '+tip); };
document.getElementById('kaydetBtn').onclick=()=>{ let fNo=document.getElementById('faturaNo').value.trim(); if(!fNo){ showToast('Fatura no giriniz!',true); return; } let mKod=document.getElementById('musteriKod').value.trim(); if(!mKod){ showToast('Müşteri kodu giriniz!',true); return; } let urunler=[], miktarlar=[], fiyatlar=[], iskontolar=[]; document.querySelectorAll('#faturaTable tbody .urun-satir').forEach(row=>{ let k=row.querySelector('.urun-kod').value.trim(); if(k){ urunler.push(k); miktarlar.push(row.querySelector('.miktar').value||0); fiyatlar.push(row.querySelector('.fiyat').value||0); iskontolar.push(row.querySelector('.iskonto').value||0); } }); if(urunler.length===0){ showToast('En az bir ürün giriniz!',true); return; } let fd=new FormData(); fd.append('fatura_no',fNo); fd.append('musteri_kod',mKod); fd.append('tarih',document.getElementById('tarih').value); fd.append('vade',document.getElementById('vade').value); fd.append('odeme_tipi',document.getElementById('odemeTipi').value); fd.append('genel_toplam',document.getElementById('genelToplam').innerText.replace(' TL','')); urunler.forEach((k,i)=>{ fd.append('urun_kod[]',k); fd.append('miktar[]',miktarlar[i]); fd.append('fiyat[]',fiyatlar[i]); fd.append('iskonto[]',iskontolar[i]); }); fetch('ajax/fatura_kaydet.php',{method:'POST',body:fd}).then(r=>r.json()).then(data=>{ if(data.success){ document.getElementById('excelBtn').style.display='inline-block'; document.getElementById('pdfBtn').style.display='inline-block'; document.getElementById('excelBtn').onclick=()=>window.location.href='exports/excel_export.php?fatura_id='+data.fatura_id; document.getElementById('pdfBtn').onclick=()=>window.location.href='exports/pdf_export.php?fatura_id='+data.fatura_id; if(data.ref_no) document.getElementById('refNoGoster').innerText=data.ref_no; showToast('Fatura kaydedildi! No: '+fNo); }else{ showToast('Hata: '+data.error,true); } }); };
document.addEventListener('keydown', (e) => { let key=e.key; if(key==='F1'||key==='F10'){ e.preventDefault(); document.getElementById('kaydetBtn').click(); } else if(key==='F2'){ e.preventDefault(); document.getElementById('musteriKod').focus(); } else if(key==='F3'){ e.preventDefault(); let fr=document.querySelector('#faturaTable .urun-kod'); if(fr) fr.focus(); } else if(key==='F7'){ e.preventDefault(); document.getElementById('toggleOdeme').click(); } else if(key==='F8'){ e.preventDefault(); showToast('Tahsilat ekranı açılacak'); } else if(key==='F9'){ e.preventDefault(); window.location.href='satis_faturasi_dokumu.php'; } else if(key==='F11'){ e.preventDefault(); openCalculator(); } else if(key==='F12'){ e.preventDefault(); urunModalGoster(); } else if(key==='Escape'){ let cm=document.getElementById('calcModal'); let um=document.getElementById('urunModal'); if(cm && cm.style.display==='flex') closeCalculator(); else if(um && um.style.display==='flex') urunModalKapat(); else if(confirm('Ana menüye dön?')) window.location.href='index.php'; } });
document.addEventListener('DOMContentLoaded',()=>{ let fr=document.querySelector('#faturaTable .urun-satir'); if(fr) attachRowEvents(fr); let fi=document.querySelector('#faturaTable .urun-kod'); if(fi) fi.focus(); });
