window.addEventListener('DOMContentLoaded', () => { faturaYukle({ fatura_no:'<?= $duzenleData['fatura_no'] ?>', tarih:'<?= $duzenleData['tarih'] ?>', vade:<?= $duzenleData['vade']??0 ?>, odeme_tipi:'<?= $duzenleData['odeme_tipi'] ?>', musteri_kod:'<?= $duzenleData['musteri_kod'] ?>', musteri_adi:'<?= addslashes($duzenleData['musteri_adi']) ?>', vergi_no:'<?= $duzenleData['vergi_no'] ?>', efatura_tipi:'<?= $duzenleData['efatura_tipi'] ?>', iskonto_orani:<?= $duzenleData['iskonto_orani']??0 ?>, satirlar:<?= json_encode($duzenleData['satirlar']) ?> }); });
<?php endif; ?>
function faturaYukle(f){ document.getElementById('faturaNo').value=f.fatura_no; document.getElementById('tarih').value=f.tarih; document.getElementById('vade').value=f.vade||0; document.getElementById('odemeTipi').value=f.odeme_tipi; document.getElementById('toggleOdeme').innerHTML='💰 '+f.odeme_tipi+' <kbd>F7</kbd>'; document.getElementById('musteriKod').value=f.musteri_kod; document.getElementById('musteriBilgi').innerHTML='<strong>'+f.musteri_adi+'</strong><br>Vergi No: '+(f.vergi_no||'-')+' - '+f.efatura_tipi+'<br>🏷️ İskonto: %'+(f.iskonto_orani||0); window.musteriIskonto=f.iskonto_orani||0; let tb=document.querySelector('#faturaTable tbody'); tb.innerHTML=''; if(f.satirlar && f.satirlar.length>0){ f.satirlar.forEach(s=>{ let nr=addNewRow(); nr.querySelector('.urun-kod').value=s.urun_kod; nr.querySelector('.urun-ad').value=s.urun_adi; nr.querySelector('.birim').value=s.birim_adi||''; nr.querySelector('.miktar').value=s.miktar; nr.querySelector('.fiyat').value=s.birim_fiyat; nr.querySelector('.iskonto').value=s.iskonto_orani||0; hesaplaTutar(nr); }); }else{ addNewRow(); } genelToplamHesapla(); showToast('Fatura '+f.fatura_no+' yüklendi'); }
</script>
</body>
</html>